/**
 * Bundles a slimmed snapshot of the Admin API OpenAPI spec into the package.
 *
 * Usage: node scripts/bundle-spec.mjs
 *
 * Reads:  docs/api-reference/admin.yaml (rswag-generated — never hand-edit)
 * Writes: src/generated/admin-spec.json (committed; regenerated by `pnpm build`)
 *
 * The snapshot keeps what `spree api endpoints` / `spree api schema` need —
 * operation metadata, parameters, request/response schemas, the scope lines
 * rswag writes into descriptions, and component schemas for $ref resolution —
 * and strips examples and code samples, which dominate the YAML's size.
 */

import * as fs from 'node:fs'
import * as path from 'node:path'
import { fileURLToPath } from 'node:url'
import { parse } from 'yaml'

const here = path.dirname(fileURLToPath(import.meta.url))
const SPEC_PATH = path.resolve(here, '../../../docs/api-reference/admin.yaml')
const OUT_PATH = path.resolve(here, '../src/generated/admin-spec.json')

function stripExamples(node) {
  if (Array.isArray(node)) {
    for (const item of node) stripExamples(item)
    return
  }
  if (node && typeof node === 'object') {
    delete node.example
    delete node.examples
    delete node['x-codeSamples']
    for (const value of Object.values(node)) stripExamples(value)
  }
}

const spec = parse(fs.readFileSync(SPEC_PATH, 'utf-8'))
stripExamples(spec)

const slim = {
  info: spec.info,
  paths: spec.paths,
  components: { schemas: spec.components?.schemas ?? {} },
}

fs.mkdirSync(path.dirname(OUT_PATH), { recursive: true })
fs.writeFileSync(OUT_PATH, JSON.stringify(slim))

const HTTP_METHODS = new Set(['get', 'post', 'put', 'patch', 'delete'])
const size = (fs.statSync(OUT_PATH).size / 1024).toFixed(0)
const operations = Object.values(slim.paths ?? {}).reduce(
  (n, methods) => n + Object.keys(methods).filter((m) => HTTP_METHODS.has(m)).length,
  0,
)
console.log(
  `admin-spec.json written: ${size} KB, ${Object.keys(slim.paths ?? {}).length} paths, ${operations} operations`,
)
